/**
 * AZURE categories as a Record
 */
export const azureCategories: Record<string, IconCategory> = Object.fromEntries(
  azureCategoriesArray.map((cat) => [cat.label, cat])
);

/**
 * Get all AZURE icons
 */
export const getAllAzureIcons = () => {
  return azureCategoriesArray.flatMap((cat) => cat.icons);
};

export default azureCategoriesArray;
